<template><el-card v-if="d"><template #header><div class="head"><b>导出记录详情</b><el-button v-if="d.downloadable" type="primary" @click="download">下载 XLSX</el-button></div></template><el-descriptions border :column="2"><el-descriptions-item v-for="(v,k) in d" :key="k" :label="k">{{v}}</el-descriptions-item></el-descriptions></el-card></template>
<script setup>import{ref,onMounted}from'vue';import{useRoute}from'vue-router';import{getExport,downloadExport}from'../../api/exports';const route=useRoute(),d=ref();onMounted(async()=>d.value=await getExport(route.params.id));async function download(){const r=await downloadExport(route.params.id),blob=r.data||r;const a=document.createElement('a');a.href=URL.createObjectURL(blob);a.download=d.value.fileName;a.click();URL.revokeObjectURL(a.href);d.value=await getExport(route.params.id)}</script><style scoped>.head{display:flex;justify-content:space-between}</style>
